import java.util.Scanner;

public class Solution {
    public static void main(String[] args) {
        Scanner terminalInput = new Scanner(System.in);
        System.out.println("Status: Waiting for Data Injection...");

        // 1. Declare and read an int named 'id'
        System.out.print("ID: ");
        int id = terminalInput.nextInt();

        // 2. Declare and read a double named 'price'
        System.out.print("Price: ");
        double price = terminalInput.nextDouble();

        // 3. Print the result: "ID: [id] | Price: [price]"
        System.out.println("ID: " + id + " | Price: " + price);
    }
}
